import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from './hooks/useAuth';

/**
 * Authentication page. Since Firebase has been removed, this page
 * prompts the user for their name and stores it in localStorage.
 * Once a name is provided, the user is considered "logged in" and
 * redirected to the main application. If the user is already
 * authenticated (a valid auth object exists in localStorage), they
 * will be redirected immediately without seeing this form.
 */
export const Auth = () => {
  const [nameInput, setNameInput] = useState('');
  const navigate = useNavigate();
  const { isAuth } = useAuth();

  // Redirect authenticated users to the home page
  useEffect(() => {
    if (isAuth) {
      navigate('/app');
    }
  }, [isAuth, navigate]);

  const handleLogin = () => {
    const trimmedName = nameInput.trim();
    if (!trimmedName) return;
    const authInfo = {
      name: trimmedName,
      userID: Date.now().toString(),
      photo: null,
      isAuth: true,
    };
    localStorage.setItem('auth', JSON.stringify(authInfo));
    navigate('/app');
  };

  return (
    <div className="flex items-center justify-center min-h-screen bg-gray-100 px-4">
      <div className="bg-white rounded-lg shadow-lg p-8 w-full max-w-md">
        <h1 className="text-3xl font-bold mb-2 text-center text-blue-600">Budget Buddy</h1>
        <p className="text-sm text-gray-600 mb-6 text-center">
          Your simple personal budget companion
        </p>
        <input
          type="text"
          placeholder="Enter your name"
          value={nameInput}
          onChange={(e) => setNameInput(e.target.value)}
          className="w-full p-3 border border-gray-300 rounded mb-4 focus:outline-none focus:ring-2 focus:ring-blue-400"
        />
        <button
          onClick={handleLogin}
          className="w-full bg-blue-500 hover:bg-blue-600 text-white py-3 rounded transition-colors"
        >
          Continue
        </button>
      </div>
    </div>
  );
};
